exercise.solution_code:
#include <iostream>

int main()
{
    int a{}, b{}, c{};
    std::cin >> a >> b >> c;

    int storedPositive{ 0 };
    {
        int positiveSum{ 0 };
        if (a > 0) positiveSum += a;
        if (b > 0) positiveSum += b;
        if (c > 0) positiveSum += c;
        storedPositive = positiveSum;
    }

    int storedNegative{ 0 };
    {
        int negativeSum{ 0 };
        if (a < 0) negativeSum += a;
        if (b < 0) negativeSum += b;
        if (c < 0) negativeSum += c;
        storedNegative = negativeSum;
    }

    int total{ storedPositive + storedNegative };

    std::cout << "Positive sum: " << storedPositive << '\n';
    std::cout << "Negative sum: " << storedNegative << '\n';
    std::cout << "Total: "        << total           << '\n';

    return 0;
}
